import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import './Pages.css';

const KatthaAccounts = () => {
  const [language, setLanguage] = useState('en');
  const [customers, setCustomers] = useState([]);
  const [searchName, setSearchName] = useState('');
  const [filteredCustomers, setFilteredCustomers] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [summary, setSummary] = useState({
    purchaseCount: 0,
    totalPaid: 0,
    pendingBalance: 0
  });
  const [loading, setLoading] = useState(false);

  const translations = {
    en: {
      katthaAccounts: 'Kattha Accounts',
      searchCustomer: 'Search Customer',
      noData: 'No customer selected',
      purchases: 'Purchases',
      paid: 'Paid',
      balance: 'Balance'
    },
    te: {
      katthaAccounts: 'ఖత్తా ఖాతాలు',
      searchCustomer: 'కస్టమర్‌ని శోధించండి',
      noData: 'ఏ ఖాతాలు చేర్చబడలేదు',
      purchases: 'కొనుగోళ్లు',
      paid: 'చెల్లించారు',
      balance: 'శేషం'
    },
    hi: {
      katthaAccounts: 'खत्ता खाते',
      searchCustomer: 'ग्राहक खोजें',
      noData: 'कोई ग्राहक चयनित नहीं',
      purchases: 'खरीदारी',
      paid: 'भुगतान',
      balance: 'शेष'
    }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchCustomers();
  }, []);

  const uniqueCustomers = useMemo(() => {
    const map = new Map();
    customers.forEach((customer) => {
      if (!map.has(customer.customerName)) {
        map.set(customer.customerName, customer);
      }
    });
    return Array.from(map.values());
  }, [customers]);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/customers', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCustomers(response.data.accounts || []);
    } catch (err) {
      console.error('Error fetching customers:', err);
    }
  };

  const fetchCustomerSummary = async (customerId) => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`http://localhost:5000/api/bills/customer/${customerId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });

      const bills = response.data.bills || [];
      const purchaseCount = bills.length;
      const totalPaid = bills.reduce((sum, bill) => sum + (bill.paidAmount || 0), 0);
      const pendingBalance = bills.reduce((sum, bill) => sum + (bill.pendingAmount || 0), 0);

      setSummary({ purchaseCount, totalPaid, pendingBalance });
    } catch (err) {
      console.error('Error fetching customer summary:', err);
      setSummary({ purchaseCount: 0, totalPaid: 0, pendingBalance: 0 });
    } finally {
      setLoading(false);
    }
  };

  const handleSearchChange = (value) => {
    setSearchName(value);
    if (!value.trim()) {
      setFilteredCustomers([]);
      setShowSuggestions(false);
      return;
    }

    const filtered = uniqueCustomers.filter((customer) =>
      customer.customerName.toLowerCase().includes(value.toLowerCase())
    );

    setFilteredCustomers(filtered);
    setShowSuggestions(filtered.length > 0);
  };

  const handleSelectSuggestion = async (customer) => {
    setSearchName(customer.customerName);
    setShowSuggestions(false);
    setSelectedCustomer(customer);
    await fetchCustomerSummary(customer._id);
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />
      <div className="main-content">
        <div className="top-bar">
          <h1>{t.katthaAccounts}</h1>
          <select
            value={language}
            onChange={(e) => setLanguage(e.target.value)}
            className="language-selector"
          >
            <option value="en">English</option>
            <option value="te">Telugu</option>
            <option value="hi">Hindi</option>
          </select>
        </div>

        <div className="page-card">
          <div className="form-group" style={{ position: 'relative' }}>
            <label>{t.searchCustomer}</label>
            <input
              type="text"
              value={searchName}
              onChange={(e) => handleSearchChange(e.target.value)}
              placeholder={t.searchCustomer}
              style={{ width: '100%', padding: '10px' }}
            />
            {showSuggestions && filteredCustomers.length > 0 && (
              <div
                style={{
                  position: 'absolute',
                  top: '100%',
                  left: 0,
                  right: 0,
                  background: '#fff',
                  border: '1px solid #ddd',
                  zIndex: 1000,
                  maxHeight: 220,
                  overflowY: 'auto'
                }}
              >
                {filteredCustomers.map((customer) => (
                  <div
                    key={customer._id}
                    onClick={() => handleSelectSuggestion(customer)}
                    style={{
                      padding: '10px',
                      borderBottom: '1px solid #f0f0f0',
                      cursor: 'pointer'
                    }}
                  >
                    <div>{customer.customerName}</div>
                    <small>{customer.phone || customer.village || ''}</small>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="customer-summary" style={{ marginTop: 24 }}>
            {loading ? (
              <p>Loading...</p>
            ) : !selectedCustomer ? (
              <p>{t.noData}</p>
            ) : (
              <div>
                <h2>{selectedCustomer.customerName}</h2>
                <div style={{ display: 'grid', gap: 16, gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))' }}>
                  <div className="summary-card">
                    <strong>{t.purchases}</strong>
                    <p>{summary.purchaseCount}</p>
                  </div>
                  <div className="summary-card">
                    <strong>{t.paid}</strong>
                    <p>₹ {summary.totalPaid.toFixed(2)}</p>
                  </div>
                  <div className="summary-card">
                    <strong>{t.balance}</strong>
                    <p>₹ {summary.pendingBalance.toFixed(2)}</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default KatthaAccounts;
